public static async Task<ChatClientAgent> ProvideAgent(IWorkflowTreeViewModel tree, AgentHelper helper)
{
    // Erstellt einen unabhängigen Arbeitsbereich
    var scope = tree.AsAgentScope()
        .WithPromptLanguage(AgentLanguages.English)   // Standardsprache für Prompt-Vorlagen
        .WithOutputLanguage(AgentLanguages.Chinese)   // Standardsprache für die Ausgabe
        .WithAutoDiscovery(assemblyName: "Lib") // Automatische Komponentenerkennung aus der Assembly
        .WithAutoMarkDirty(false)               // Ob die Ansicht automatisch als „geändert“ markiert wird
        .WithMaxToolCalls(200)                  // Maximale Anzahl von Tool-Aufrufen
        .WithToolCallCallback(args =>           // Rückruf bei Tool-Aufruf
        {
            helper.ToolCalled?.Invoke();
            return Task.CompletedTask;
        })
        .WithSelectionHandler(async args => // Der Agent fragt den Benutzer, welche Aktion ausgeführt werden soll
        {
            if (helper.SelectionHandler is not null)
                await helper.SelectionHandler(args);
        })
        .WithConfirmationHandler(async args => // Der Agent bestätigt mit dem Benutzer die Berechtigung zur Ausführung einer Aktion
        {
            if (helper.ConfirmationHandler is not null)
                await helper.ConfirmationHandler(args);
        });

    // Aggressivitätsgrad der Interaktionswerkzeuge: 0 bis 3
    scope.WithInteractionSafety(helper.InteractionSafety); 
    // Registriert benutzerdefinierte Prompt-Überschreibungen für Sicherheitsstufen (gilt nur für Stufen 1 bis 3)
    foreach (var kvp in helper.InteractionSafetyPrompts)
        scope.WithInteractionSafetyPrompt(kvp.Key, kvp.Value);

    // Progressiver Kontext
    var contextPrompt = scope.ProvideProgressiveContextPrompt();

    // Erstellt den MAF-Tool-Satz
    var tools = scope.ProvideTools();

    var apiKey = Environment.GetEnvironmentVariable(EnvironmentVariableName);

    var chatClient = new OpenAIClient(
        new ApiKeyCredential(apiKey),
        new OpenAIClientOptions
        {
            Endpoint = new Uri(Endpoint)
        }).GetChatClient(string.IsNullOrWhiteSpace(Model) ? "qwen-plus" : Model)
          .AsIChatClient();

    var agent = chatClient.AsAIAgent(
        instructions: contextPrompt,
        tools: tools);

    return agent;
}

